1	export class MathematicalFunctions {
2		static roundToPrecision({
3			value,
4			precision,
5		}: {
6			value: number;
7			precision: number | null;
8		}): number {
9			if (typeof value !== 'number') {
10				throw new Error('Input must be a number');
11			}
12	
13			if (precision !== null && typeof precision !== 'number') {
14				throw new Error('Precision must be a number or null');
15			}
16	
17			if (precision === null) return value;
18	
19			const factor = Math.pow(10, precision);
20			return Math.round(value * factor) / factor;
21		}
22	
23		/**
24		 * Calculates the mean of an array of numbers.
25		 * Physical meaning: It represents the average value of a set of numbers.
26		 */
27		static mean({
28			values,
29			precision,
30		}: {
31			values: number[];
32			precision: number | null;
33		}): number {
34			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
35				throw new Error('Input must be an array of numbers');
36			}
37	
38			if (values.length === 0) return 0;
39			const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
40			return precision ? this.roundToPrecision({ value: mean, precision }) : mean;
41		}
42	
43		/**
44		 * Calculates the median of an array of numbers.
45		 * The median is the middle value when the numbers are sorted.
46		 * Physical meaning: It represents the central tendency of a set of numbers, less affected by outliers than the mean.
47		 */
48		static median({ values }: { values: number[] }): number {
49			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
50				throw new Error('Input must be an array of numbers');
51			}
52	
53			if (values.length === 0) {
54				throw new Error('Cannot calculate median of empty array');
55			}
56	
57			const sorted = [...values].sort((a, b) => a - b);
58			const mid = Math.floor(sorted.length / 2);
59	
60			if (sorted.length % 2 === 0) {
61				const midLeft = sorted[mid - 1];
62				const midRight = sorted[mid];
63				if (midLeft === undefined || midRight === undefined) {
64					throw new Error('Unexpected undefined value in sorted array');
65				}
66				return (midLeft + midRight) / 2;
67			} else {
68				const midValue = sorted[mid];
69				if (midValue === undefined) {
70					throw new Error('Unexpected undefined value in sorted array');
71				}
72				return midValue;
73			}
74		}
75	
76		/**
77		 * Calculates the variance of an array of numbers.
78		 * Variance is the average of the squared differences from the mean.
79		 * Physical meaning: It measures how far a set of numbers are spread out from their average value.
80		 */
81		static variance({
82			values,
83			precision,
84		}: {
85			values: number[];
86			precision: number | null;
87		}): number {
88			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
89				throw new Error('Input must be an array of numbers');
90			}
91	
92			if (values.length === 0) return 0;
93			const meanVal = this.mean({ values, precision });
94	
95			if (precision !== null) {
96				const value =
97					values.reduce((sum, val) => sum + Math.pow(val - meanVal, 2), 0) / values.length;
98				return this.roundToPrecision({ value, precision });
99			}
100	
101			return (
102				values.reduce((sum, val) => sum + Math.pow(val - meanVal, 2), 0) / values.length
103			);
104		}
105	
106		/**	 * Calculates the median absolute deviation (MAD) of an array of numbers.
107		 * MAD is the median of the absolute deviations from the median.
108		 * Physical meaning: It measures the variability of a set of values, robust to outliers.
109		 */
110		static medianAbsoluteDeviation({ values }: { values: number[] }): number {
111			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
112				throw new Error('Input must be an array of numbers');
113			}
114	
115			if ([0, 1].includes(values.length)) return 0;
116	
117			const median = this.median({ values });
118			const deviations = values.map((val) => Math.abs(val - median));
119			return this.median({ values: deviations });
120		}
121	
122		/**
123		 * Calculates the standard deviation of an array of numbers.
124		 * Standard deviation is the square root of the variance.
125		 * Physical meaning: It measures the amount of variation or dispersion in a set of values.
126		 */
127		static standardDeviation({
128			values,
129			precision,
130		}: {
131			values: number[];
132			precision: number | null;
133		}): number {
134			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
135				throw new Error('Input must be an array of numbers');
136			}
137	
138			if (values.length === 0) return 0;
139			if (precision !== null) {
140				const value = this.variance({ values, precision });
141				return this.roundToPrecision({ value: Math.sqrt(value), precision });
142			}
143			return Math.sqrt(this.variance({ values, precision: null }));
144		}
145	
146		/**
147		 * Calculates the linear regression parameters (slope, intercept, r-squared) for two arrays of numbers.
148		 * linear regression is a statistical method to model the relationship between two variables.
149		 * It finds the best-fitting line through the data points.
150		 * Physical meaning: It helps to understand the relationship between two variables and predict one variable based on the other.
151		 */
152		static linearRegression({ x, y }: { x: number[]; y: number[] }): {
153			slope: number;
154			intercept: number;
155			rSquared: number;
156		} {
157			if (!Array.isArray(x) || !Array.isArray(y)) {
158				throw new Error('Input must be arrays');
159			}
160	
161			if (x.length === 0 || y.length === 0) {
162				throw new Error('Input arrays must have the same non-zero length');
163			}
164	
165			if (x.length !== y.length) {
166				throw new Error('Input arrays must have the same non-zero length');
167			}
168			if (
169				x.some((val) => typeof val !== 'number') ||
170				y.some((val) => typeof val !== 'number')
171			) {
172				throw new Error('Input arrays must contain only numbers');
173			}
174	
175			const n = x.length;
176			const sumX = x.reduce((sum, val) => sum + val, 0);
177			const sumY = y.reduce((sum, val) => sum + val, 0);
178			const sumXY = x.reduce((sum, val, i) => sum + val * (y[i] ?? 0), 0);
179			const sumXX = x.reduce((sum, val) => sum + val * val, 0);
180	
181			const denominator = n * sumXX - sumX * sumX;
182	
183			if (Math.abs(denominator) < 1e-10) {
184				const yMean = this.mean({ values: y, precision: null });
185				return { slope: 0, intercept: yMean, rSquared: 0 };
186			}
187	
188			const slope = (n * sumXY - sumX * sumY) / denominator;
189			const intercept = (sumY - slope * sumX) / n;
190	
191			const yMean = this.mean({ values: y, precision: null });
192			const totalSumSquares = y.reduce((sum, val) => sum + Math.pow(val - yMean, 2), 0);
193			const residualSumSquares = y.reduce((sum, val, i) => {
194				const predicted = slope * (x[i] ?? 0) + intercept;
195				return sum + Math.pow(val - predicted, 2);
196			}, 0);
197	
198			const rSquared =
199				residualSumSquares === 0 && totalSumSquares === 0
200					? 0
201					: 1 - residualSumSquares / totalSumSquares;
202	
203			return { slope, intercept, rSquared };
204		}
205	
206		/**
207		 * Calculates the moving average of an array of numbers.
208		 * The moving average smooths the data by averaging values over a specified window size.
209		 * Physical meaning: It helps to identify trends in time series data by reducing noise.
210		 */
211		static movingAverage({
212			values,
213			windowSize,
214			precision,
215		}: {
216			values: number[];
217			windowSize: number;
218			precision: number | null;
219		}): number[] {
220			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
221				throw new Error('Input must be an array of numbers');
222			}
223	
224			if (typeof windowSize !== 'number' || windowSize <= 0) {
225				throw new Error('Window size must be a positive number');
226			}
227	
228			if (precision !== null && typeof precision !== 'number') {
229				throw new Error('Precision must be a number or null');
230			}
231	
232			if (values.length === 0) return [];
233	
234			if (windowSize <= 0 || windowSize > values.length) {
235				throw new Error('Invalid window size');
236			}
237	
238			const result: number[] = [];
239	
240			for (let i = 0; i <= values.length - windowSize; i++) {
241				const window = values.slice(i, i + windowSize);
242				result.push(this.mean({ values: window, precision }));
243			}
244			return result;
245		}
246		/**
247		 * Calculates the Fourier coefficients for a given set of values.
248		 * Fourier coefficients represent the amplitudes of sine and cosine waves that can reconstruct the original signal.
249		 * Physical meaning: They decompose a signal into its frequency components, allowing analysis of periodic patterns.
250		 * Read wiki for more info.
251		 */
252		static fourierCoefficients({
253			values,
254			period,
255			harmonics,
256			precision,
257		}: {
258			values: number[];
259			period: number;
260			harmonics: number;
261			precision: number | null;
262		}): {
263			a: number[];
264			b: number[];
265		} {
266			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
267				throw new Error('Input must be an array of numbers');
268			}
269			if (typeof period !== 'number' || period <= 0) {
270				throw new Error('Period must be a positive number');
271			}
272			if (typeof harmonics !== 'number' || harmonics <= 0) {
273				throw new Error('Harmonics must be a positive number');
274			}
275			if (precision !== null && typeof precision !== 'number') {
276				throw new Error('Precision must be a number or null');
277			}
278	
279			if (values.length === 0) return { a: [], b: [] };
280	
281			const n = values.length;
282			const a: number[] = [];
283			const b: number[] = [];
284	
285			for (let k = 1; k <= harmonics; k++) {
286				let aK = 0;
287				let bK = 0;
288	
289				for (let t = 0; t < n; t++) {
290					const angle = (2 * Math.PI * k * t) / period;
291					const val = values[t] ?? 0;
292					aK += val * Math.cos(angle);
293					bK += val * Math.sin(angle);
294				}
295	
296				aK = (2 * aK) / n;
297				bK = (2 * bK) / n;
298	
299				if (precision !== null) {
300					aK = this.roundToPrecision({ value: aK, precision });
301					bK = this.roundToPrecision({ value: bK, precision });
302				}
303	
304				a.push(aK);
305				b.push(bK);
306			}
307	
308			return { a, b };
309		}
310	
311		/**
312		 * Reconstructs a Fourier series from the coefficients.
313		 * This method uses the Fourier coefficients to reconstruct the original signal.
314		 * Physical meaning: It allows the synthesis of a signal from its frequency components.
315		 */
316		static reconstructFourierSeries({
317			period,
318			harmonics,
319			a,
320			b,
321			length,
322			a0 = 0,
323		}: {
324			period: number;
325			harmonics: number;
326			a: number[];
327			b: number[];
328			length: number;
329			a0?: number;
330		}): number[] {
331			if (typeof period !== 'number' || period <= 0 || !Number.isFinite(period)) {
332				throw new Error('Period must be a positive finite number');
333			}
334			if (period > 1e10) {
335				throw new Error('Period is too large and may cause numerical precision issues');
336			}
337			if (typeof harmonics !== 'number' || harmonics <= 0 || !Number.isInteger(harmonics)) {
338				throw new Error('Harmonics must be a positive integer');
339			}
340			if (!Array.isArray(a) || !Array.isArray(b)) {
341				throw new Error('Fourier coefficients must be arrays');
342			}
343	
344			if (
345				a.some((val) => typeof val !== 'number' || !Number.isFinite(val)) ||
346				b.some((val) => typeof val !== 'number' || !Number.isFinite(val))
347			) {
348				throw new Error('Fourier coefficients must contain only finite numbers');
349			}
350	
351			if (a.length !== harmonics || b.length !== harmonics) {
352				throw new Error('Fourier coefficients must have the same length as harmonics');
353			}
354	
355			if (typeof length !== 'number' || length <= 0) {
356				throw new Error('Length must be a positive number');
357			}
358	
359			if (typeof a0 !== 'number' || !Number.isFinite(a0)) {
360				throw new Error('DC component (a0) must be a finite number');
361			}
362	
363			const result: number[] = [];
364	
365			for (let t = 0; t < length; t++) {
366				let value = a0;
367				for (let k = 1; k <= harmonics; k++) {
368					const angle = (2 * Math.PI * k * t) / period;
369					value += (a[k - 1] ?? 0) * Math.cos(angle) + (b[k - 1] ?? 0) * Math.sin(angle);
370				}
371				result.push(value);
372			}
373	
374			return result;
375		}
376	
377		/**
378		 * Detects change points using PELT algorithm with statistical validation.
379		 * Change points are where statistical properties change significantly.
380		 * Physical meaning: Identifies structural breaks in time series data.
381		 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
382		 * cspell:ignore Changepoints meanvar
383		 */
384		static changePointDetection({
385			values,
386			minSegmentLength = Math.max(1, Math.floor(values.length * 0.1)),
387			penalty = Math.max(Math.log(values.length) * 2, 10e-20),
388			method = 'mean' as 'mean' | 'variance' | 'meanvar',
389			significance = 0.1,
390		}: {
391			values: number[];
392			minSegmentLength?: number;
393			penalty?: number;
394			method?: 'mean' | 'variance' | 'meanvar';
395			significance?: number;
396		}): {
397			changePoints: number[];
398			cost: number;
399			segments: { start: number; end: number; mean: number; variance: number }[];
400		} {
401			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
402				throw new Error('Input must be an array of numbers');
403			}
404	
405			if (
406				typeof minSegmentLength !== 'number' ||
407				minSegmentLength < 1 ||
408				!Number.isInteger(minSegmentLength)
409			) {
410				throw new Error('Minimum segment length must be at least 1');
411			}
412	
413			if (typeof penalty !== 'number' || penalty < 0) {
414				throw new Error('Penalty must be a non-negative number');
415			}
416	
417			if (!['mean', 'variance', 'meanvar'].includes(method)) {
418				throw new Error(`Unknown method: ${method}`);
419			}
420	
421			if (typeof significance !== 'number' || significance <= 0 || significance >= 1) {
422				throw new Error('Significance level must be between 0 and 1');
423			}
424	
425			if (values.length === 0) {
426				return { changePoints: [], cost: 0, segments: [] };
427			}
428	
429			if (values.length < minSegmentLength * 2) {
430				return {
431					changePoints: [],
432					cost: this.segmentCost({ values, start: 0, end: values.length - 1, method }),
433					segments: [
434						{
435							start: 0,
436							end: values.length - 1,
437							mean: this.mean({ values, precision: null }),
438							variance: this.variance({ values, precision: null }),
439						},
440					],
441				};
442			}
443	
444			const dataLength = values.length;
445			const optimalCosts: number[] = Array.from({ length: dataLength + 1 }, () => Infinity);
446			const lastChangePoints: number[] = Array.from({ length: dataLength + 1 }, () => -1);
447	
448			optimalCosts[0] = 0;
449	
450			for (let timePoint = minSegmentLength; timePoint <= dataLength; timePoint++) {
451				let bestCost = Infinity;
452				let bestChangePoint = -1;
453	
454				for (
455					let previousChangePoint = 0;
456					previousChangePoint <= timePoint - minSegmentLength;
457					previousChangePoint++
458				) {
459					const currentOptimalCost = optimalCosts[previousChangePoint];
460					if (currentOptimalCost !== undefined && currentOptimalCost !== Infinity) {
461						const segmentCost = this.segmentCost({
462							values,
463							start: previousChangePoint,
464							end: timePoint - 1,
465							method,
466						});
467						const totalCost = currentOptimalCost + segmentCost + penalty;
468	
469						if (totalCost < bestCost) {
470							bestCost = totalCost;
471							bestChangePoint = previousChangePoint;
472						}
473					}
474				}
475	
476				if (bestChangePoint !== -1) {
477					optimalCosts[timePoint] = bestCost;
478					lastChangePoints[timePoint] = bestChangePoint;
479				}
480			}
481	
482			const changePoints: number[] = [];
483			let currentPosition = dataLength;
484			let lastChangePoint = lastChangePoints[currentPosition];
485			while (
486				lastChangePoint !== undefined &&
487				lastChangePoint !== -1 &&
488				lastChangePoint !== 0
489			) {
490				changePoints.unshift(lastChangePoint);
491				currentPosition = lastChangePoint;
492				lastChangePoint = lastChangePoints[currentPosition];
493			}
494	
495			const validatedChangePoints = this.validateChangePoints({
496				values,
497				changePoints,
498				significance,
499				method,
500			});
501	
502			const segments = this.buildSegments({ values, changePoints: validatedChangePoints });
503	
504			const finalCost = optimalCosts[dataLength];
505			return {
506				changePoints: validatedChangePoints,
507				cost: finalCost ?? Infinity,
508				segments,
509			};
510		}
511	
512		/**
513		 * Applies exponential smoothing to an array of numbers.
514		 * Exponential smoothing is a time series forecasting method for univariate data.
515		 * Physical meaning: It gives more weight to recent observations, making it useful for forecasting.
516		 */
517		static exponentialSmoothing({
518			values,
519			alpha = 0.3,
520		}: {
521			values: number[];
522			alpha?: number;
523		}): number[] {
524			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
525				throw new Error('Input must be an array of numbers');
526			}
527	
528			if (typeof alpha !== 'number' || alpha < 0 || alpha > 1) {
529				throw new Error('Alpha must be a number between 0 and 1');
530			}
531	
532			if (values.length === 0) return [];
533	
534			const firstValue = values[0];
535			if (firstValue === undefined) return [];
536	
537			const result: number[] = [firstValue];
538			for (let i = 1; i < values.length; i++) {
539				const currentValue = values[i] ?? 0;
540				const previousResult = result[i - 1] ?? 0;
541				const smoothed = alpha * currentValue + (1 - alpha) * previousResult;
542				result.push(smoothed);
543			}
544	
545			return result;
546		}
547	
548		/**
549		 * Calculates the trend line using linear regression.
550		 * The trend line represents the general direction of the data over time.
551		 * Physical meaning: It helps to identify long-term trends in time series data.
552		 */
553		static calculateTrend({
554			values,
555			dates,
556		}: {
557			values: number[];
558			dates: string[];
559		}): number[] {
560			if (!Array.isArray(values) || !Array.isArray(dates)) {
561				throw new Error('Input must be arrays');
562			}
563	
564			if (values.length === 0 || dates.length === 0) {
565				return [];
566			}
567	
568			if (values.some((val) => typeof val !== 'number')) {
569				throw new Error('Values array must contain only numbers');
570			}
571	
572			if (dates.some((date) => typeof date !== 'string')) {
573				throw new Error('Dates array must contain only strings');
574			}
575	
576			if (dates.length !== values.length) {
577				throw new Error('Values and dates arrays must have the same length');
578			}
579	
580			if (dates.some((date) => isNaN(new Date(date).getTime()))) {
581				throw new Error('All dates must be valid date strings');
582			}
583	
584			const timestamps = dates.map((date) => new Date(date).getTime());
585			const baseTime = timestamps[0] as unknown as number;
586			const x = timestamps.map((t) => (t - baseTime) / (1000 * 60 * 60 * 24));
587	
588			const { slope, intercept } = this.linearRegression({ x, y: values });
589			return x.map((t) => slope * t + intercept);
590		}
591	
592		/**
593		 * Removes outliers from an array of numbers using z-score method.
594		 * Outliers are values that deviate significantly from the mean.
595		 * Physical meaning: It helps to clean the data by removing extreme values that may skew analysis.
596		 */
597		static removeOutliers({
598			values,
599			threshold = 2.5,
600		}: {
601			values: number[];
602			threshold?: number;
603		}): number[] {
604			if (!Array.isArray(values) || values.some((val) => typeof val !== 'number')) {
605				throw new Error('Input must be an array of numbers');
606			}
607	
608			if (threshold && typeof threshold !== 'number') {
609				throw new Error('Threshold must be a number');
610			}
611	
612			if (values.length < 3) return values; // Insufficient data
613	
614			const median = this.median({ values });
615			const mad = this.medianAbsoluteDeviation({ values });
616	
617			return values.map((val) => {
618				const modifiedZScore = (0.6745 * Math.abs(val - median)) / mad;
619				return modifiedZScore > threshold ? median : val;
620			});
621		}
622	
623		/**
624		 * Calculate cost of a segment based on negative log-likelihood
625		 * This method calculates the cost of a segment based on the negative log-likelihood of the data.
626		 * Physical meaning: It quantifies how well the segment fits a statistical model, with lower costs indicating better fit.
627		 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
628		 */
629		private static segmentCost({
630			values,
631			start,
632			end,
633			method,
634		}: {
635			values: number[];
636			start: number;
637			end: number;
638			method: string;
639		}): number {
640			const segment = values.slice(start, end + 1);
641			const n = segment.length;
642			if (n === 0) return Infinity;
643			if (n === 1) return 0;
644	
645			const variance = this.variance({ values: segment, precision: null });
646	
647			switch (method) {
648				case 'mean':
649					return variance === 0 ? 0 : n * Math.log(Math.max(variance, 1e-10));
650				case 'variance':
651				case 'meanvar':
652					return variance === 0
653						? 0
654						: n * Math.log(Math.max(2 * Math.PI * variance, 1e-10)) + n;
655				default:
656					throw new Error(`Unknown method: ${method}`);
657			}
658		}
659	
660		/**
661		 * Validate change points using likelihood ratio test
662		 * This method checks if the detected change points are statistically significant.
663		 * It uses the likelihood ratio test to determine if the change points represent significant shifts in the data.
664		 * Physical meaning: It ensures that the detected change points are not due to random fluctuations in the data.
665		 * Based on Killick et al. (2012) "Optimal Detection of Changepoints With a Linear Computational Cost"
666		 */
667		private static validateChangePoints({
668			values,
669			changePoints,
